import{_ as o,c as d,o as i,a1 as t,j as e,a,t as n}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"紹介: OpenCode Agent Skills | opencode-agent-skills","description":"OpenCode Agent Skillsの核心価値と主要機能を学びます。動的スキル検出、コンテキスト注入、圧縮回復などの特性をマスターし、Claude Code互換と自動推奨をサポートします。","frontmatter":{"title":"紹介: OpenCode Agent Skills | opencode-agent-skills","sidebarTitle":"AIにスキルを理解させる","subtitle":"紹介: OpenCode Agent Skills","description":"OpenCode Agent Skillsの核心価値と主要機能を学びます。動的スキル検出、コンテキスト注入、圧縮回復などの特性をマスターし、Claude Code互換と自動推奨をサポートします。","tags":["入門ガイド","プラグイン紹介"],"prerequisite":[],"order":1},"headers":[],"relativePath":"ja/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md","filePath":"ja/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md"}'),r={name:"ja/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md"},p={tabindex:"0"};function u(s,l,c,h,g,k){return i(),d("div",null,[l[8]||(l[8]=t(`<h1 id="opencode-agent-skillsとは" tabindex="-1">OpenCode Agent Skillsとは？ <a class="header-anchor" href="#opencode-agent-skillsとは" aria-label="Permalink to &quot;OpenCode Agent Skillsとは？&quot;">​</a></h1><h2 id="このコースでできること" tabindex="-1">このコースでできること <a class="header-anchor" href="#このコースでできること" aria-label="Permalink to &quot;このコースでできること&quot;">​</a></h2><ul><li>OpenCode Agent Skillsプラグインの核心価値を理解する</li><li>プラグインが提供する主要機能特性を習得する</li><li>スキルが自動的に検出・ロードされる仕組みを理解する</li><li>本プラグインと他のスキル管理ソリューションの違いを区別する</li></ul><h2 id="今の課題" tabindex="-1">今の課題 <a class="header-anchor" href="#今の課題" aria-label="Permalink to &quot;今の課題&quot;">​</a></h2><p>以下のような状況に遭遇したことがあるかもしれません：</p><ul><li><strong>スキルの分散管理が困難</strong>：スキルがプロジェクト、ユーザーディレクトリ、プラグインキャッシュなど複数の場所に散らばっており、適切なスキルが見つからない</li><li><strong>セッションが長くなると手間が増える</strong>：長時間のセッション後、以前ロードしたスキルがコンテキスト圧縮により無効になる</li><li><strong>互換性への懸念</strong>：Claude Codeから移行した後、既存のスキルやプラグインが使えなくなるのではないかと心配</li><li><strong>設定を繰り返す必要がある</strong>：各プロジェクトでスキルを再設定する必要があり、統一されたスキル管理メカニズムが不足している</li></ul><p>これらの問題がAIアシスタントの使用効率に影響を与えています。</p><h2 id="コアコンセプト" tabindex="-1">コアコンセプト <a class="header-anchor" href="#コアコンセプト" aria-label="Permalink to &quot;コアコンセプト&quot;">​</a></h2><p><strong>OpenCode Agent Skills</strong>は、OpenCodeに動的スキル検出・管理能力を提供するプラグインシステムです。</p><div class="info custom-block"><p class="custom-block-title">スキルとは？</p><p>スキル（Skill）は、AIワークフローのガイダンスを含む再利用可能なモジュールです。通常は <code>SKILL.md</code> ファイル（スキルの機能と使用方法を記述）を含むディレクトリであり、補助ファイル（ドキュメント、スクリプトなど）が含まれる場合もあります。</p></div><p><strong>核心価値</strong>：標準化されたスキル形式（SKILL.md）を通じて、プロジェクト間・セッション間でのスキル再利用を実現します。</p><h3 id="技術アーキテクチャ" tabindex="-1">技術アーキテクチャ <a class="header-anchor" href="#技術アーキテクチャ" aria-label="Permalink to &quot;技術アーキテクチャ&quot;">​</a></h3><p>プラグインは TypeScript + Bun + Zod で開発され、4つのコアツールを提供します：</p><table tabindex="0"><thead><tr><th>ツール</th><th>機能</th></tr></thead><tbody><tr><td><code>use_skill</code></td><td>スキルのSKILL.md内容をセッションコンテキストに注入</td></tr><tr><td><code>read_skill_file</code></td><td>スキルディレクトリ内のサポートファイル（ドキュメント、設定など）を読み取り</td></tr><tr><td><code>run_skill_script</code></td><td>スキルディレクトリのコンテキストで実行可能なスクリプトを実行</td></tr><tr><td><code>get_available_skills</code></td><td>現在使用可能なスキルリストを取得</td></tr></tbody></table><h2 id="主要機能特性" tabindex="-1">主要機能特性 <a class="header-anchor" href="#主要機能特性" aria-label="Permalink to &quot;主要機能特性&quot;">​</a></h2><h3 id="_1-動的スキル検出" tabindex="-1">1. 動的スキル検出 <a class="header-anchor" href="#_1-動的スキル検出" aria-label="Permalink to &quot;1. 動的スキル検出&quot;">​</a></h3><p>プラグインは複数の場所から自動的にスキルを検出し、優先順位でソートします：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. .opencode/skills/              (プロジェクトレベル - OpenCode)</span></span>
<span class="line"><span>2. .claude/skills/                (プロジェクトレベル - Claude Code)</span></span>
<span class="line"><span>3. ~/.config/opencode/skills/     (ユーザーレベル - OpenCode)</span></span>
<span class="line"><span>4. ~/.claude/skills/              (ユーザーレベル - Claude Code)</span></span>
<span class="line"><span>5. ~/.claude/plugins/cache/        (プラグインキャッシュ)</span></span>
<span class="line"><span>6. ~/.claude/plugins/marketplaces/ (インストール済みプラグイン)</span></span></code></pre></div><p><strong>ルール</strong>：最初に一致したスキルが有効になり、後続の同名スキルは無視されます。</p><blockquote><p>なぜこの設計に？</p><p>プロジェクトレベルのスキルがユーザーレベルのスキルより優先されるため、プロジェクトで特定の動作をカスタマイズしても、グローバル設定には影響しません。</p></blockquote><h3 id="_2-コンテキスト注入" tabindex="-1">2. コンテキスト注入 <a class="header-anchor" href="#_2-コンテキスト注入" aria-label="Permalink to &quot;2. コンテキスト注入&quot;">​</a></h3><p><code>use_skill</code> を呼び出すと、スキル内容がXML形式でセッションコンテキストに注入されます：</p><ul><li><code>noReply: true</code> - AIは注入されたメッセージに応答しない</li><li><code>synthetic: true</code> - システムが生成したメッセージとしてマーク（UIに表示されず、ユーザー入力にはカウントされない）</li></ul><p>つまり、スキル内容はセッションコンテキストに永続的に存在し、セッションが成長してコンテキスト圧縮が発生しても、スキルは引き続き使用可能です。</p><h3 id="_3-圧縮回復メカニズム" tabindex="-1">3. 圧縮回復メカニズム <a class="header-anchor" href="#_3-圧縮回復メカニズム" aria-label="Permalink to &quot;3. 圧縮回復メカニズム&quot;">​</a></h3><p>OpenCodeがコンテキスト圧縮を実行すると（長時間セッションでよく行われる操作）、プラグインは <code>session.compacted</code> イベントを監視し、自動的に使用可能なスキルリストを再注入します。</p><p>これにより、AIは長時間セッションでも常に使用可能なスキルを認識し、圧縮によってスキルアクセス能力を失うことがありません。</p><h3 id="_4-claude-code互換" tabindex="-1">4. Claude Code互換 <a class="header-anchor" href="#_4-claude-code互換" aria-label="Permalink to &quot;4. Claude Code互換&quot;">​</a></h3><p>プラグインはClaude Codeのスキル・プラグインシステムと完全に互換しており、以下をサポートしています：</p><ul><li>Claude Codeスキル（<code>.claude/skills/&lt;skill-name&gt;/SKILL.md</code>）</li><li>Claudeプラグインキャッシュ（<code>~/.claude/plugins/cache/...</code>）</li><li>Claudeプラグインマーケットプレース（<code>~/.claude/plugins/marketplaces/...</code>）</li></ul><p>つまり、以前Claude Codeを使用していた場合、OpenCodeに移行した後でも既存のスキルとプラグインを使用できます。</p><h3 id="_5-自動スキル推奨" tabindex="-1">5. 自動スキル推奨 <a class="header-anchor" href="#_5-自動スキル推奨" aria-label="Permalink to &quot;5. 自動スキル推奨&quot;">​</a></h3><p>プラグインはメッセージを監視し、意味的類似度を使用して使用可能なスキルに関連しているかを検出します：</p><ul><li>メッセージのembeddingベクトルを計算</li><li>すべてのスキルの説明と余弦類似度を計算</li><li>類似度がしきい値を超えた場合、AIが関連スキルをロードするよう推奨する評価プロンプトを注入</li></ul><p>このプロセスは完全に自動化されており、スキル名を記憶したり明示的に要求したりする必要はありません。</p><h3 id="_6-superpowers統合-オプション" tabindex="-1">6. Superpowers統合（オプション） <a class="header-anchor" href="#_6-superpowers統合-オプション" aria-label="Permalink to &quot;6. Superpowers統合（オプション）&quot;">​</a></h3><p>プラグインはSuperpowersワークフローをサポートし、環境変数で有効化できます：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> opencode</span></span></code></pre></div><p>有効化すると、プラグインは自動的に <code>using-superpowers</code> スキルを検出し、セッション初期化時に完全なワークフローガイダンスを注入します。</p><h2 id="他のソリューションとの比較" tabindex="-1">他のソリューションとの比較 <a class="header-anchor" href="#他のソリューションとの比較" aria-label="Permalink to &quot;他のソリューションとの比較&quot;">​</a></h2>`,40)),e("table",p,[l[7]||(l[7]=e("thead",null,[e("tr",null,[e("th",null,"ソリューション"),e("th",null,"特徴"),e("th",null,"適用シーン")])],-1)),e("tbody",null,[l[4]||(l[4]=e("tr",null,[e("td",null,[e("strong",null,"opencode-agent-skills")]),e("td",null,"動的検出、圧縮回復、自動推奨"),e("td",null,"統一管理と自動推奨が必要なシーン")],-1)),e("tr",null,[l[2]||(l[2]=e("td",null,[e("strong",null,"opencode-skills")],-1)),e("td",null,[l[0]||(l[0]=a("自動的に ",-1)),e("code",null,"skills_"+n(s.name),1),l[1]||(l[1]=a(" ツールとして登録",-1))]),l[3]||(l[3]=e("td",null,"独立したツール呼び出しが必要なシーン",-1))]),l[5]||(l[5]=e("tr",null,[e("td",null,[e("strong",null,"superpowers")]),e("td",null,"完全なソフトウェア開発ワークフロー"),e("td",null,"厳密なプロセス規範が必要なプロジェクト")],-1)),l[6]||(l[6]=e("tr",null,[e("td",null,[e("strong",null,"skillz")]),e("td",null,"MCPサーバーモード"),e("td",null,"ツールをまたいでスキルを使用するシーン")],-1))])]),l[9]||(l[9]=t('<p>本プラグインを選ぶ理由：</p><ul><li>✅ <strong>設定不要</strong>：スキルの自動検出・管理</li><li>✅ <strong>スマートな推奨</strong>：意味的マッチングに基づく自動推奨</li><li>✅ <strong>圧縮回復</strong>：長時間セッションで安定・信頼性が高い</li><li>✅ <strong>互換性</strong>：Claude Codeスキルのシームレスな移行</li></ul><h2 id="本講のまとめ" tabindex="-1">本講のまとめ <a class="header-anchor" href="#本講のまとめ" aria-label="Permalink to &quot;本講のまとめ&quot;">​</a></h2><p>OpenCode Agent Skillsプラグインは、動的検出、コンテキスト注入、圧縮回復などのコアメカニズムを通じて、OpenCodeに完全なスキル管理能力を提供します。その核心価値は：</p><ul><li><strong>自動化</strong>：手動設定とスキル名の記憶を軽減</li><li><strong>安定性</strong>：長時間セッションでもスキルは常に使用可能</li><li><strong>互換性</strong>：既存のClaude Codeエコシステムとシームレスに統合</li></ul><h2 id="次回の予告" tabindex="-1">次回の予告 <a class="header-anchor" href="#次回の予告" aria-label="Permalink to &quot;次回の予告&quot;">​</a></h2><blockquote><p>次回は <strong><a href="./../installation/">OpenCode Agent Skillsのインストール</a></strong> を学びます。</p><p>学ぶこと：</p><ul><li>OpenCode設定にプラグインを追加する方法</li><li>プラグインが正しくインストールされているか確認する方法</li><li>ローカル開発モードの設定方法</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を展開</strong></summary><blockquote><p>更新日時：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>プラグインエントリと機能概要</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L1-L12" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>1-12</td></tr><tr><td>コア機能特性リスト</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/README.md#L5-L11" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>5-11</td></tr><tr><td>スキル検出優先順位</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L241-L246" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>241-246</td></tr><tr><td>合成メッセージ注入</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L147-L162" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>147-162</td></tr><tr><td>圧縮回復メカニズム</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L144-L151" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>144-151</td></tr><tr><td>意味的マッチングモジュール</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/embeddings.ts#L108-L135" target="_blank" rel="noreferrer"><code>src/embeddings.ts</code></a></td><td>108-135</td></tr></tbody></table><p><strong>重要な定数</strong>：</p><ul><li><code>EMBEDDING_MODEL = &quot;Xenova/all-MiniLM-L6-v2&quot;</code>：使用するembeddingモデル</li><li><code>SIMILARITY_THRESHOLD = 0.35</code>：意味的類似度のしきい値</li><li><code>TOP_K = 5</code>：自動推奨で返すスキル数の上限</li></ul><p><strong>重要な関数</strong>：</p><ul><li><code>discoverAllSkills()</code>：複数の場所からスキルを検出</li><li><code>use_skill()</code>：スキル内容をセッションコンテキストに注入</li><li><code>matchSkills()</code>：意味的類似度に基づいて関連スキルをマッチング</li><li><code>injectSyntheticContent()</code>：合成メッセージをセッションに注入</li></ul></details>',10))])}const C=o(r,[["render",u]]);export{m as __pageData,C as default};
